var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"황금나무시여. 저희의 아이들이 무사히 낙원으로 향할 수 있게 해주세요.","JPN":"黄金の木よ。我々の子どもたちが無事楽園に向かうことができますように。","ENG":"Oh, Golden Tree. I beg that you allow our children a safe passageway to the Promised Land.","TWN":"黃金樹，請保佑我們的孩子們能平安前往樂園。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"종말의 굴레를 벗어나, 낙원에서 새로이 시작할 수 있기를.","JPN":"終末の束縛から開放され、楽園で新しい生活を始められますように。","ENG":"So that they can break free from the shackles of the Apocalypse Augury and start anew.","TWN":"希望他們能擺脫末日的枷鎖，在樂園重新開始生活。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"문은 그만 두드려, 모르가나. 그러다 전송장치까지 고장 나면 어쩌려고 그래?","JPN":"もうドアを叩くのはやめてよ、モルガナ。伝送装置が壊れたらどうするんだ。","ENG":"Stop knocking on the door, Morgana. What if you break the transmission device?","TWN":"別再敲了，莫甘娜。要是把傳送裝置弄壞了怎麼辦？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"넌 낙원으로 먼저 가 있어. 그루터기는 나랑 어른들이 지킬 테니까.","JPN":"お前は先に楽園に行って。切り株は僕と大人たちが守るから。","ENG":"You go ahead to the Promised Land. The adults and I will defend the Stump.","TWN":"你就先去樂園吧，木墩由我和大人來守護。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이거 열어, 카롤리스.","JPN":"ここを開けて、カロリス。","ENG":"Open it, Karolis.","TWN":"打開這個，卡羅黎斯。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"너 같이 약한 꼬맹이가 무슨 수로 그루터기를 지킨단 거야?","JPN":"あなたみたいに弱い子どもがどうやって切り株を守るっていうのよ。","ENG":"How can a weak kid like you possibly defend the Stump?","TWN":"像你這麼弱的小鬼，怎麼守護木墩？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"쳇, 지금은 내가 너보다 세거든?","JPN":"ちっ、今は僕のほうがお前より強いんだよ。","ENG":"Tch! I'm stronger than you right now!","TWN":"嘖，現在我比你強好吧？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"아마도…","JPN":"たぶんな……","ENG":"I think...","TWN":"可能吧…"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"지금까지… 그렇게 노력했는데…","JPN":"今まで……あんなに頑張ってきたのに……","ENG":"I... worked so hard, but...","TWN":"到現在為止…我已經那麼努力了…"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"왜 가장 중요한 순간에 내가… 이런 곳에 있어야 하는 거냐고.","JPN":"なんで一番大事な時にあたしが……こんなところにいないとダメなの？","ENG":"why do I have to be here... at the most important moment?","TWN":"為什麼在最重要的時刻，我卻…在這種地方。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"솔직히 난, 네가 낙원으로 가는 사람 중 하나라서 다행이라 생각해.","JPN":"正直に言うと僕は、お前が楽園に行けて良かったと思う。","ENG":"To be honest, I'm relieved that you're one of the people going to the Promised Land.","TWN":"說實話，我覺得你能去樂園真是太好了。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"누가 뭐래도 넌 그루터기를 위해 가장 노력한 사람이니까.","JPN":"誰が何と言おうと、お前は切り株のために一番頑張ってきた人だから。","ENG":"Because you worked the hardest in the Stump.","TWN":"不管別人怎麼說，你是為了木墩最努力的人。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"다행이라고…?","JPN":"よかった……？","ENG":"You're relieved...?","TWN":"太好了…？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"지금까지 지켜온 것들을 전부 버리고 도망치는 게… 내가 한 일의 대가라는 거야?","JPN":"今まで守ってきたものを捨てて逃げることが……あたしがやってきたことの対価だってこと？","ENG":"So abandoning everything I protected and running away... is what I get for what I've done?","TWN":"放棄一直守護的東西逃跑…這就是我所做事情的代價嗎？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"어쩔 수 없잖아!","JPN":"仕方ないだろ！","ENG":"There's nothing left!","TWN":"那是沒辦法的事！"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"할 수만 있다면, 나도 모두가 이곳에서 평화롭게 살았으면 좋겠어!","JPN":"僕だって、本当はみんなとここで平和に暮らしたい。","ENG":"If I could, I want everyone to live peacefully here!","TWN":"如果可以的話，我也希望大家能在這裡和平生活！"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"떠나야만 한다면, 모두가 함께 떠나면 좋겠다고!","JPN":"ここから出ていくなら、みんなと一緒がいい！","ENG":"If we have to leave, I want everyone to leave together!","TWN":"如果必須離開的話，也希望大家能一起離開！"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"하지만 지금 우린 <color=#ffd34c>선택</color>해야하잖아! 가장 최선이라 생각하는 방법을 골랐을 뿐이야!","JPN":"でも今僕たちは<color=#ffd34c>選択</color>を迫られているんだ！　今はこれが最善なんだよ！","ENG":"But we must <color=#ffd34c>choose</color>! And we chose what we thought was best!","TWN":"但是現在我們必須<color=#ffd34c>選擇</color>！我們只是選擇了看似最好的方法！"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"우리가 예언을 믿는 건 정해진 결말에 순응하기 위해서가 아니야, 귀염둥이.","JPN":"アタシたちが予言を信じるのは決められた結末に従うためじゃないわ、可愛子ちゃん。","ENG":"We do not believe in prophecies to conform to a predetermined outcome, cutie.","TWN":"我們相信預言，並不是為了順從既定的結局，小可愛。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"어차피 바꿀 수 없는 미래라면, 가장 후회 없는 선택을 하는 편이 후련하지 않겠어?","JPN":"どうせ変えられない未来なら、もっとも悔いのない選択をした方がいいんじゃない？","ENG":"If we cannot change the future, would it not be best for you to make decisions resulting in the fewest regrets?","TWN":"如果未來無法改變，做出最不後悔的選擇不是更好嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"저기… 방금 소리친 건 미안…","JPN":"えっと……さっきは大声出してごめん……","ENG":"Hey... I'm sorry for yelling at you...","TWN":"那個…抱歉，剛才吼你…"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"작별인사 하려고 온 건데… 내가 너무 쓸데없는 소릴 해버렸네.","JPN":"別れの挨拶をしに来たのに……余計なことを言っちゃったよ。","ENG":"I came here to say goodbye... and all I did was say something stupid.","TWN":"我是來道別的…結果說了些多餘的話。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"카롤리스.","JPN":"カロリス。","ENG":"Karolis.","TWN":"卡羅黎斯。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};